function advancePhase(){if(state.phase==='prep'){openPrepPanel();return;}if(state.phase==='morning'){state.phase='afternoon';state.phaseElapsed=0;state.energy=Math.min(state.maxEnergy,state.energy+1);showPhaseToast('進入下午營業，恢復 1 點體力');}else if(state.phase==='afternoon'){state.phase='evening';state.phaseElapsed=0;showPhaseToast('晚間營業開始');}else if(state.phase==='evening'){closeDay();return;}else if(state.phase==='closed'){showReport();return;}save();render();}
function phaseTick(){if(!isOperating())return;state.phaseElapsed=(state.phaseElapsed||0)+1;if(state.phaseElapsed>=(state.phaseDuration||45))advancePhase();renderDayFlow();save();}
function startDayClock(){clearInterval(dayClockTimer);dayClockTimer=setInterval(phaseTick,1000);}
function dailyGrade(){const served=state.servedCustomers||0,clean=state.cleanliness||0,rep=state.dailyRep||0;const score=served*7+clean*.3+rep*2+(state.energy||0)*2;if(score>=105)return ['S','完美營業'];if(score>=78)return ['A','非常受歡迎'];if(score>=50)return ['B','營運順利'];if(score>=30)return ['C','仍有改善空間'];return ['D','今天有些手忙腳亂'];}
