function renderRoster(){els.roster.innerHTML=catActors.map((cat,i)=>{const s=catStat(cat.id);return `<button class="cat-card ${i===0?'active':''}" type="button"><img src="${CAT_PORTRAITS[cat.art]}" alt="${cat.name}"><div><b>${cat.name}</b><small>等級 ${8+i}｜${cat.pose==='walk'?'巡店中':(cat.pose==='sleep'?'休息中':'閒逛中')}</small><i><span style="width:${Math.min(100,s.mood)}%"></span></i><small>🍽️ ${s.satiety}%　🙂 ${s.mood}%　💗 ${s.bond}</small></div></button>`}).join('')+`<button type="button" class="cat-detail-btn" id="catDetailBtn">查看詳情 🐾</button>`;}

