function reactionText(cat,key){const arr=(CAT_REACTIONS[cat.id]&&CAT_REACTIONS[cat.id][key])||[];return arr.length?arr[Math.floor(Math.random()*arr.length)]:`${cat.name} 看起來很開心。`;}
function interactionEls(){return {wrap:$('#catInteraction'),title:$('#interactionTitle')};}
function showInteractionStep(id){['catSelectStep','foodSelectStep','feedStageStep','groomStageStep','playStageStep'].forEach(x=>$('#'+x)?.classList.toggle('active',x===id));}
function openCatInteraction(mode){if(state.phase==='closed')return toast('今天已經打烊');if(state.energy<1)return toast('體力不足，請進入下一天恢復');interactionMode=mode;interactionCatId=null;const e=interactionEls();e.wrap.classList.remove('hidden');const labels={feed:'🥣 選擇要餵食的貓咪',groom:'🪮 選擇要梳毛的貓咪',play:'🪶 選擇一起玩耍的貓咪'};const copies={feed:'今天想餵哪一隻貓咪？',groom:'今天想替哪一隻貓咪整理毛髮？',play:'今天想陪哪一隻貓咪玩羽毛棒？'};e.title.textContent=labels[mode];$('#catSelectCopy').textContent=copies[mode];renderCatChoices();showInteractionStep('catSelectStep');}
function closeCatInteraction(){interactionEls().wrap.classList.add('hidden');interactionMode=null;interactionCatId=null;groomTracking=false;stopPlayTimer();}
function renderCatChoices(){const grid=$('#catChoiceGrid');grid.innerHTML=CAT_PROFILES.map(cat=>{const s=catStat(cat.id);return `<button type="button" class="cat-choice" data-cat-id="${cat.id}"><img src="${CAT_PORTRAITS[cat.art]}" alt="${cat.name}"><b>${cat.name}</b><span class="personality-chip">${cat.personalityIcon} ${cat.personality}</span><small>🍽️ ${s.satiety}　🙂 ${s.mood}</small><small>💗 親密 ${s.bond}</small></button>`}).join('');grid.querySelectorAll('[data-cat-id]').forEach(btn=>btn.addEventListener('click',()=>selectInteractionCat(btn.dataset.catId)));}
function selectInteractionCat(id){interactionCatId=id;const cat=catProfile(id);const titles={feed:`🥣 餵食 ${cat.name}`,groom:`🪮 替 ${cat.name} 梳毛`,play:`🪶 和 ${cat.name} 玩耍`};$('#interactionTitle').textContent=titles[interactionMode];if(interactionMode==='feed'){renderFoods();showInteractionStep('foodSelectStep');}else if(interactionMode==='groom'){startGrooming();showInteractionStep('groomStageStep');}else{startPlayGame();showInteractionStep('playStageStep');}}
function renderFoods(){const cat=catProfile(interactionCatId),grid=$('#foodChoiceGrid');grid.innerHTML=CAT_INTERACTION_FOODS.map(f=>{const fav=cat.favoriteFood===f.id,dis=cat.dislikedFood===f.id;return `<button type="button" class="food-card ${fav?'favorite':''} ${dis?'disliked':''}" data-food-id="${f.id}"><span>${f.icon}</span><b>${f.name}</b><small>${f.desc}<br>🪙 ${f.cost}</small>${fav?'<em class="food-tag">最喜歡</em>':dis?'<em class="food-tag">不太喜歡</em>':''}</button>`}).join('');grid.querySelectorAll('[data-food-id]').forEach(btn=>btn.addEventListener('click',()=>performFeed(btn.dataset.foodId)));}
function applyCareEnergy(kind){state.energy-=1;state.prepActions=state.prepActions||{};state.prepActions[kind]=(state.prepActions[kind]||0)+1;state.catCare=(state.catCare||0)+1;renderDayFlow();renderPrepPanel();}
function performFeed(foodId){const food=CAT_INTERACTION_FOODS.find(f=>f.id===foodId),cat=catProfile(interactionCatId),s=catStat(interactionCatId);if(!food||!cat)return;if(state.coins<food.cost)return toast('金幣不足，請選擇其他食物');if(state.energy<1)return toast('體力不足');state.coins-=food.cost;const favorite=cat.favoriteFood===food.id,disliked=cat.dislikedFood===food.id;let sat=food.satiety,mood=food.mood,bond=food.bond;if(favorite){mood+=6;bond+=3;}if(disliked){mood=Math.max(1,mood-8);bond=1;}if(cat.id==='hana')sat+=5;if(cat.id==='bean'&&favorite)bond+=1;s.satiety=Math.min(100,s.satiety+sat);s.mood=Math.min(100,s.mood+mood);s.bond=Math.min(100,s.bond+bond);const actor=catActors.find(a=>a.id===cat.id);if(actor)actor.mood=s.mood;applyCareEnergy('feed');const img=$('#feedCatImage');img.src=CAT_PORTRAITS[cat.art];img.className='interaction-cat '+(disliked?'grumpy':favorite?'happy':'eating');$('#foodBowl').textContent=food.icon;$('#foodBowl').classList.add('show');$('#feedReaction').textContent=disliked?'…？':favorite?'💗✨💗':'♪ 💕';$('#feedMessage').textContent=reactionText(cat,disliked?'feedDislike':favorite?'feedFav':'feedNormal');$('#feedChanges').innerHTML=`<div><small>🍽️ 飽足度</small><b>+${sat}</b></div><div><small>🙂 心情</small><b>+${mood}</b></div><div><small>💗 親密度</small><b>+${bond}</b></div>`;showInteractionStep('feedStageStep');renderStats();renderRoster();save();}
function startGrooming(){const cat=catProfile(interactionCatId);groomCount=0;groomStart=null;groomTracking=false;$('#groomCatImage').src=CAT_PORTRAITS[cat.art];$('#groomCatImage').className='interaction-cat';$('#groomReaction').textContent='';$('#groomMessage').textContent=`${cat.personalityIcon} ${cat.personality}：${reactionText(cat,'groom')}`;$('#groomChanges').classList.add('hidden');$('#groomDoneBtn').classList.add('hidden');$('#groomProgress').querySelectorAll('i').forEach(i=>i.classList.remove('done'));$('#groomInstruction').textContent=`慢慢替 ${cat.name} 梳理毛髮`;}
function groomPointerPos(ev){const r=$('#groomZone').getBoundingClientRect();return {x:ev.clientX-r.left,y:ev.clientY-r.top,w:r.width,h:r.height};}
function addGroomSpark(x,y){const el=document.createElement('span');el.className='groom-spark';el.textContent=['✨','💛','♪'][Math.floor(Math.random()*3)];el.style.left=x+'px';el.style.top=y+'px';$('#groomZone').appendChild(el);setTimeout(()=>el.remove(),800);}
function finishGroomStroke(end){if(!groomStart)return;const dx=end.x-groomStart.x,dy=Math.abs(end.y-groomStart.y);const longEnough=Math.abs(dx)>end.w*.28&&dy<end.h*.38;if(longEnough){groomCount=Math.min(3,groomCount+1);$('#groomProgress').querySelectorAll('i').forEach((i,n)=>i.classList.toggle('done',n<groomCount));addGroomSpark(end.x,end.y);$('#groomCatImage').className='interaction-cat happy';$('#groomReaction').textContent=groomCount<3?'✨ 呼嚕…':'💗✨ 完成！';$('#groomMessage').textContent=groomCount<3?`梳理得很舒服，再完成 ${3-groomCount} 次。`:reactionText(catProfile(interactionCatId),'groom');if(groomCount>=3)completeGrooming();}else{$('#groomCatImage').className='interaction-cat grumpy';$('#groomReaction').textContent='！';$('#groomMessage').textContent=interactionCatId==='latte'?'拿鐵扭來扭去，請放慢速度再試一次。':'滑動距離太短或太斜，試著沿著背部慢慢梳。';}}
function completeGrooming(){const cat=catProfile(interactionCatId),s=catStat(interactionCatId);if(state.energy<1)return toast('體力不足');let clean=22,mood=7,bond=4;if(cat.id==='snow'){clean+=8;mood+=3;}if(cat.id==='latte'){mood=4;bond=3;}s.clean=Math.min(100,s.clean+clean);s.mood=Math.min(100,s.mood+mood);s.bond=Math.min(100,s.bond+bond);const actor=catActors.find(a=>a.id===cat.id);if(actor)actor.mood=s.mood;applyCareEnergy('groom');$('#groomChanges').innerHTML=`<div><small>✨ 清潔度</small><b>+${clean}</b></div><div><small>🙂 心情</small><b>+${mood}</b></div><div><small>💗 親密度</small><b>+${bond}</b></div>`;$('#groomChanges').classList.remove('hidden');$('#groomDoneBtn').classList.remove('hidden');renderRoster();save();}
function randomPlayTarget(){const target=$('#playTarget');if(!target)return;playTargetPos={x:18+Math.random()*64,y:20+Math.random()*50};target.style.left=playTargetPos.x+'%';target.style.top=playTargetPos.y+'%';}
function stopPlayTimer(){playActive=false;if(playTimerId){clearInterval(playTimerId);playTimerId=null;}}
function startPlayGame(){const cat=catProfile(interactionCatId);playScore=0;playCombo=0;playTime=15;playLastHit=0;$('#playTarget').style.display='grid';$('#featherToy').style.display='block';$('#playCatImage').src=CAT_PORTRAITS[cat.art];$('#playCatImage').className='play-cat '+(cat.playStyle==='shy'?'shy':'');$('#playMessage').textContent=`${cat.personalityIcon} ${cat.personality}：${reactionText(cat,'play')}`;$('#playChanges').classList.add('hidden');$('#playDoneBtn').classList.add('hidden');$('#playResultTitle').classList.add('hidden');$('#playTimer').textContent='⏱️ 15';$('#playCombo').textContent='連擊 0';$('#playScore').textContent='得分 0';randomPlayTarget();stopPlayTimer();playActive=true;playTimerId=setInterval(()=>{playTime--;$('#playTimer').textContent='⏱️ '+playTime;if(playTime<=0)finishPlayGame();},1000);}
function playPointer(ev){const r=$('#playZone').getBoundingClientRect();return{x:Math.max(0,Math.min(r.width,ev.clientX-r.left)),y:Math.max(0,Math.min(r.height,ev.clientY-r.top)),w:r.width,h:r.height};}
function addPlayTrail(x,y){const el=document.createElement('span');el.className='play-trail';el.textContent=['✨','⭐','💫'][Math.floor(Math.random()*3)];el.style.left=x+'px';el.style.top=y+'px';$('#playZone').appendChild(el);setTimeout(()=>el.remove(),700);}
function moveFeather(ev){if(!playActive)return;const p=playPointer(ev),feather=$('#featherToy'),catImg=$('#playCatImage');feather.style.left=p.x+'px';feather.style.top=p.y+'px';catImg.style.left=(22+(p.x/p.w)*56)+'%';catImg.style.bottom=Math.max(18,70-(p.y/p.h)*48)+'px';if(Math.random()<.12)addPlayTrail(p.x,p.y);const tx=playTargetPos.x/100*p.w,ty=playTargetPos.y/100*p.h,dist=Math.hypot(p.x-tx,p.y-ty),now=Date.now();if(dist<48&&now-playLastHit>550){playLastHit=now;playCombo++;const cat=catProfile(interactionCatId);playScore+=10+playCombo*2+(cat.playBonus||0)*3;$('#playCombo').textContent='連擊 '+playCombo;$('#playScore').textContent='得分 '+playScore;$('#playReaction').textContent=playCombo>=5?'🔥 超投入！':'✨ 撲到！';catImg.classList.remove('pounce','zoom');void catImg.offsetWidth;catImg.classList.add(cat.playStyle==='active'?'zoom':'pounce');randomPlayTarget();}}
function finishPlayGame(){if(!playActive)return;stopPlayTimer();const cat=catProfile(interactionCatId),s=catStat(interactionCatId);if(state.energy<1)return toast('體力不足');const tier=playScore>=110?'S':playScore>=75?'A':playScore>=40?'B':'C';let mood=5,bond=1;if(tier==='B'){mood=9;bond=2;}if(tier==='A'){mood=13;bond=3;}if(tier==='S'){mood=17;bond=5;}if(cat.playStyle==='active'){mood+=3;bond+=1;}if(cat.playStyle==='shy'&&playScore>=40)bond+=2;s.mood=Math.min(100,s.mood+mood);s.bond=Math.min(100,s.bond+bond);const actor=catActors.find(a=>a.id===cat.id);if(actor)actor.mood=s.mood;applyCareEnergy('play');$('#playTarget').style.display='none';$('#featherToy').style.display='none';$('#playResultTitle').textContent=`評價 ${tier}｜${playScore} 分`;$('#playResultTitle').classList.remove('hidden');$('#playMessage').textContent=tier==='S'?`${cat.name} 玩得超級投入，還不想停下來！`:tier==='A'?`${cat.name} 玩得很開心，尾巴不停晃動。`:tier==='B'?`${cat.name} 漸漸進入狀況，享受了這段時間。`:`${cat.name} 今天比較想慢慢來，下次再陪牠多玩一會。`;$('#playChanges').innerHTML=`<div><small>🏆 評價</small><b>${tier}</b></div><div><small>🙂 心情</small><b>+${mood}</b></div><div><small>💗 親密度</small><b>+${bond}</b></div>`;$('#playChanges').classList.remove('hidden');$('#playDoneBtn').classList.remove('hidden');renderRoster();save();}
function bindCatInteraction(){
  $('#interactionClose')?.addEventListener('click',closeCatInteraction);$('#feedDoneBtn')?.addEventListener('click',closeCatInteraction);$('#groomDoneBtn')?.addEventListener('click',closeCatInteraction);$('#playDoneBtn')?.addEventListener('click',closeCatInteraction);
  const zone=$('#groomZone');if(zone){zone.addEventListener('pointerdown',ev=>{if(groomCount>=3)return;groomTracking=true;groomStart=groomPointerPos(ev);zone.setPointerCapture?.(ev.pointerId);const b=$('#brushCursor');b.classList.add('show');b.style.left=groomStart.x+'px';b.style.top=groomStart.y+'px';ev.preventDefault();});zone.addEventListener('pointermove',ev=>{if(!groomTracking)return;const p=groomPointerPos(ev),b=$('#brushCursor');b.style.left=p.x+'px';b.style.top=p.y+'px';if(Math.random()<.22)addGroomSpark(p.x,p.y);ev.preventDefault();});const end=ev=>{if(!groomTracking)return;groomTracking=false;$('#brushCursor').classList.remove('show');finishGroomStroke(groomPointerPos(ev));ev.preventDefault();};zone.addEventListener('pointerup',end);zone.addEventListener('pointercancel',()=>{groomTracking=false;$('#brushCursor').classList.remove('show');});}
  const playZone=$('#playZone');if(playZone){playZone.addEventListener('pointerdown',ev=>{playZone.setPointerCapture?.(ev.pointerId);moveFeather(ev);ev.preventDefault();});playZone.addEventListener('pointermove',ev=>{if(ev.buttons||ev.pointerType==='touch')moveFeather(ev);ev.preventDefault();});}
}

function bindDailyControls(){
  const byId=id=>document.getElementById(id);
  const open=byId('openPrepBtn'); if(open) open.onclick=advancePhase;
  const closePrep=byId('closePrepPanel'); if(closePrep) closePrep.onclick=closePrepPanel;
  const confirmOpen=byId('confirmOpenBtn'); if(confirmOpen) confirmOpen.onclick=()=>{if(state.phase==='prep')startMorning();else closePrepPanel();};
  const nextDay=byId('nextDayBtn'); if(nextDay) nextDay.onclick=beginNextDay;
  const closeReport=byId('closeReportPanel'); if(closeReport) closeReport.onclick=()=>els.reportPanel.classList.add('hidden');
  const closeReportTop=byId('closeReportPanelTop'); if(closeReportTop) closeReportTop.onclick=()=>els.reportPanel.classList.add('hidden');
  document.querySelectorAll('[data-prep]').forEach(btn=>{btn.onclick=()=>{const kind=btn.dataset.prep;if(kind==='feed'||kind==='groom'||kind==='play'){closePrepPanel();openCatInteraction(kind);return;}const cfg={play:[1,'陪玩'],clean:[1,'清潔'],stock:[1,'備料'],special:[2,'設定今日推薦']}[kind];if(cfg)spendEnergy(cfg[0],kind,cfg[1]);};});
  const feed=byId('feedBtn'); if(feed) feed.onclick=()=>openCatInteraction('feed');
  const play=byId('playBtn'); if(play) play.onclick=()=>openCatInteraction('play');
  const groom=byId('groomBtn'); if(groom) groom.onclick=()=>openCatInteraction('groom');
}

const entranceBtn=$('#entranceSideBtn'); if(entranceBtn) entranceBtn.onclick=toggleEntranceSide;
bindDailyControls();
bindCatInteraction();
initCats(true); initCustomers(true); startDayClock(); render();
if(state.phase==='prep')setTimeout(openPrepPanel,280);

/* V0.47.2 business behavior extension */
state.version=4720;
state.dutyCats=Array.isArray(state.dutyCats)&&state.dutyCats.length?state.dutyCats.slice(0,3):['bean','latte','snow'];
state.catServiceCount=state.catServiceCount||0;
let dutyDraft=[...state.dutyCats];
const DUTY_REACTIONS={bean:'豆豆主動蹭了蹭客人的手。',coal:'煤球在桌邊安靜坐下，客人小心地摸了摸牠。',snow:'雪球優雅地靠近桌邊，蓬鬆的毛讓客人驚喜不已。',latte:'拿鐵開心跳到桌旁，逗得客人笑了出來。',hana:'花花坐在客人旁邊，眼睛卻一直看著甜點。'};
function dutyServiceScore(id){const s=catStat(id);return Math.round(s.mood*.42+s.clean*.33+Math.min(100,s.satiety)*.15+Math.min(100,s.bond)*.1);}
function dutyEligibility(id){const s=catStat(id);if(s.mood<30)return '心情太低';if(s.clean<25)return '需要梳毛';if(s.satiety<20)return '肚子餓了';return '';}
function renderDutyGrid(){const grid=document.getElementById('dutyGrid');if(!grid)return;grid.innerHTML=CAT_PROFILES.map(cat=>{const s=catStat(cat.id),selected=dutyDraft.includes(cat.id),reason=dutyEligibility(cat.id),score=dutyServiceScore(cat.id);return `<button type="button" class="duty-cat ${selected?'selected':''} ${reason?'disabled':''}" data-duty-id="${cat.id}"><img src="${CAT_PORTRAITS[cat.art]}" alt="${cat.name}"><b>${cat.name}</b><small>${cat.personalityIcon} ${cat.personality}</small><small>🙂${s.mood}　✨${s.clean}　⚡${Math.max(0,Math.round((s.mood+s.satiety)/2))}</small><small>${reason||`接客力 ${score}`}</small>${selected?'<span class="duty-check">✓</span>':''}</button>`}).join('');grid.querySelectorAll('[data-duty-id]').forEach(btn=>btn.onclick=()=>{const id=btn.dataset.dutyId;if(dutyEligibility(id))return toast(`${catProfile(id).name}${dutyEligibility(id)}，先照顧牠再安排值班`);if(dutyDraft.includes(id))dutyDraft=dutyDraft.filter(x=>x!==id);else if(dutyDraft.length<3)dutyDraft.push(id);else return toast('最多只能選擇 3 隻值班貓咪');renderDutyGrid();});const names=dutyDraft.map(id=>catProfile(id).name).join('、')||'尚未選擇';document.getElementById('dutySummary').textContent=`目前選擇 ${dutyDraft.length}/3：${names}`;}
function openDutyModal(){dutyDraft=[...(state.dutyCats||[])];renderDutyGrid();document.getElementById('dutyModal').classList.remove('hidden');}
function closeDutyModal(){document.getElementById('dutyModal').classList.add('hidden');}
function installDutyButton(){const bar=document.querySelector('.bottom');if(!bar||document.getElementById('dutyBtn'))return;const btn=document.createElement('button');btn.id='dutyBtn';btn.className='duty-btn';btn.innerHTML='<span>🐾</span><b>值班貓咪</b>';btn.onclick=openDutyModal;bar.insertBefore(btn,bar.firstChild);}
function chooseCustomerForCat(cat){return customerActors.filter(c=>(c.phase==='order'||c.phase==='dining')&&!c.catWorkerId&&!c.catServed).sort((a,b)=>(a.stay||0)-(b.stay||0))[0]||null;}
function targetNearCustomer(c){const base=c.approachCell||c.cell;const options=[{x:base.x+1,y:base.y},{x:base.x-1,y:base.y},{x:base.x,y:base.y+1},{x:base.x,y:base.y-1}].filter(p=>p.x>=0&&p.x<COLS&&p.y>=PLAYABLE_MIN_ROW&&p.y<ROWS&&isWalkable(p.x,p.y)&&isCatFloorCell(p.x,p.y));return options[0]||nearestCatCell(base);}
const _v0471CustomerStatus=customerStatus;
customerStatus=function(c){if(c.catInteractionTicks>0){const cat=catProfile(c.catWorkerId);return {cls:'dining',html:`<div class="bubble-hd"><span class="bubble-icon">💗</span><b>正在摸 ${cat?.name||'貓咪'}</b></div><small>滿意度上升，小費機率提高</small>`};}return _v0471CustomerStatus(c);};
const _v0471UpdateCatViews=updateCatViews;
updateCatViews=function(initial=false){_v0471UpdateCatViews(initial);catActors.forEach(cat=>{if(!cat.view)return;cat.view.classList.toggle('on-duty',(state.dutyCats||[]).includes(cat.id));cat.view.classList.toggle('customer-work',!!cat.workCustomerId&&cat.workPhase==='pet');cat.view.style.setProperty('--cat-unflip',cat.facing<0?-1:1);let fx=cat.view.querySelector('.cat-work-fx');if(cat.workCustomerId&&cat.workPhase==='pet'){if(!fx){fx=document.createElement('span');fx.className='cat-work-fx';fx.textContent='💗';cat.view.appendChild(fx);}}else fx?.remove();});};
const _v0471UpdateCustomerViews=updateCustomerViews;
updateCustomerViews=function(initial=false){_v0471UpdateCustomerViews(initial);customerActors.forEach(c=>{if(!c.view)return;c.view.classList.toggle('cat-petting',c.catInteractionTicks>0);});};
function showCatServiceBonus(c,cat,rep,tipBoost){if(!c.view)return;const el=document.createElement('div');el.className='service-bonus';el.textContent=`${cat.name}陪伴　人氣 +${rep}・小費加成`;c.view.appendChild(el);setTimeout(()=>el.remove(),1750);toast(DUTY_REACTIONS[cat.id]);}
function processDutyCats(){const operating=isOperating();catActors.forEach(cat=>{const duty=(state.dutyCats||[]).includes(cat.id);if(!operating||!duty){cat.workCustomerId=null;cat.workPhase=null;return;}cat.workCooldown=Math.max(0,(cat.workCooldown||0)-1);const stat=catStat(cat.id);if(dutyEligibility(cat.id)){cat.workCustomerId=null;cat.workPhase=null;return;}if(cat.workPhase==='pet'){const c=customerActors.find(x=>x.id===cat.workCustomerId);if(!c){cat.workCustomerId=null;cat.workPhase=null;cat.workCooldown=4;return;}cat.pose='sit';cat.workStay=(cat.workStay||0)-1;c.catInteractionTicks=Math.max(c.catInteractionTicks||0,2);if(cat.workStay<=0){const score=dutyServiceScore(cat.id);const rep=2+Math.floor(score/25)+(cat.id==='bean'?2:0);const tipBoost=.12+score/500+(cat.id==='latte'?.05:0);c.catBonusRep=(c.catBonusRep||0)+rep;c.catTipBoost=(c.catTipBoost||0)+tipBoost;c.catServed=true;c.catInteractionTicks=0;state.reputation+=rep;state.dailyRep=(state.dailyRep||0)+rep;state.catServiceCount=(state.catServiceCount||0)+1;state.dailyCatServices=(state.dailyCatServices||0)+1;stat.mood=Math.max(0,stat.mood-2);stat.clean=Math.max(0,stat.clean-1);stat.satiety=Math.max(0,stat.satiety-1);showCatServiceBonus(c,cat,rep,tipBoost);cat.workCustomerId=null;cat.workPhase=null;cat.workCooldown=6;save();}return;}if(cat.workCustomerId){const c=customerActors.find(x=>x.id===cat.workCustomerId);if(!c){cat.workCustomerId=null;return;}if(cat.path.length===0){cat.workPhase='pet';cat.workStay=3;c.catInteractionTicks=3;}return;}if(cat.workCooldown>0||Math.random()>.28)return;const chance=Math.max(.12,Math.min(.72,dutyServiceScore(cat.id)/125));if(Math.random()>chance)return;const c=chooseCustomerForCat(cat);if(!c)return;const target=targetNearCustomer(c),path=catBfs(cat.cell,target);if(path.length||cat.cell.x===target.x&&cat.cell.y===target.y){cat.workCustomerId=c.id;cat.workPhase=path.length?'approach':'pet';cat.workStay=3;cat.path=path;c.catWorkerId=cat.id;}});}
const _v0471StepCats=stepCats;
stepCats=function(){processDutyCats();const busy=new Set(catActors.filter(c=>c.workCustomerId).map(c=>c.id));const spots=catWalkable();catActors.forEach(cat=>{if(busy.has(cat.id)){if(cat.path.length){const next=cat.path.shift();cat.facing=projectedFacing(cat.cell,next,cat.facing);cat.cell=next;cat.frame=(cat.frame+1)%2;cat.pose='walk';}return;}if(cat.path.length){const next=cat.path.shift();cat.facing=projectedFacing(cat.cell,next,cat.facing);cat.cell=next;cat.frame=(cat.frame+1)%2;cat.pose='walk';}else if(Math.random()<.42){const target=spots[Math.floor(Math.random()*spots.length)]||cat.cell;cat.path=catBfs(cat.cell,target);if(!cat.path.length)cat.pose='sit';}else cat.pose=Math.random()<.18?'sleep':'sit';});updateCatViews(false);renderRoster();};
function settleCustomer(c){state.foodStock=Math.max(0,(state.foodStock||0)-1);state.dailyOrders=(state.dailyOrders||0)+1;const [cmin,cmax]=c.order.coins,[rmin,rmax]=c.order.rep;const quality=Math.max(0,7-Math.min(7,c.path?.length||0));const coins=cmin+Math.floor(Math.random()*(cmax-cmin+1))+quality*8;const rep=rmin+Math.floor(Math.random()*(rmax-rmin+1))+Math.floor(quality/2)+(c.catBonusRep||0);const baseTip=.48+(state.cleanliness>=70?.08:0);const tipChance=Math.min(.95,baseTip+(c.catTipBoost||0));let tip=Math.random()<tipChance?(12+Math.floor(Math.random()*38)):0;if(c.catServed)tip+=8+Math.floor(Math.random()*18);state.dailyTips=(state.dailyTips||0)+tip;state.coins+=coins+tip;state.reputation+=rep;state.dailyRevenue=(state.dailyRevenue||0)+coins+tip;state.dailyRep=(state.dailyRep||0)+rep;state.servedCustomers=(state.servedCustomers||0)+1;showIncome(c,coins,rep,tip);renderStats();save();toast(`${c.order.name} 完成：+${coins+tip} 金幣、+${rep} 人氣${c.catServed?'（貓咪陪伴加成）':''}`);}
