function claimDailyTaskReward(){if(state.taskRewardClaimed)return toast('今天的任務獎勵已經領取');if(!tasksComplete())return toast('尚未完成全部今日任務');state.taskRewardClaimed=true;state.coins+=state.taskRewardCoins;state.reputation+=state.taskRewardRep;state.dailyRevenue+=state.taskRewardCoins;state.dailyRep+=state.taskRewardRep;renderStats();renderDailyTasks();save();toast(`任務獎勵：+${state.taskRewardCoins} 金幣、+${state.taskRewardRep} 人氣`);}
function catTomorrowForecast(id){const s=catStat(id),duty=(state.dutyCats||[]).includes(id);return {satiety:Math.max(0,s.satiety-(duty?14:10)),mood:Math.max(0,s.mood-(duty?7:4)),clean:Math.max(0,s.clean-(duty?8:5))};}
