Object.entries(BASE_FURNITURE_META).forEach(([id,meta])=>{if(furniture[id]&&!furniture[id].meta)furniture[id].meta=meta;});
function furnitureMeta(id){return furniture[id]?.meta||{level:furnitureUnlockLevel(id),seats:0,function:'一般家具',comfort:0,charm:0,cleaning:0,service:0,catMood:0,preference:'一般',repBonus:0,tipBonus:0};}
function placedFurnitureEffects(){
 const total={comfort:0,charm:0,cleaning:0,service:0,catMood:0,repBonus:0,tipBonus:0,preferences:{}};
 (state.items||[]).forEach(it=>{const m=furnitureMeta(it.type);['comfort','charm','cleaning','service','catMood','repBonus','tipBonus'].forEach(k=>total[k]+=Number(m[k]||0));total.preferences[m.preference]=(total.preferences[m.preference]||0)+1;});
 total.comfort=Math.min(100,total.comfort);total.charm=Math.min(100,total.charm);total.service=Math.min(60,total.service);total.catMood=Math.min(30,total.catMood);total.repBonus=Math.min(15,total.repBonus);total.tipBonus=Math.min(30,total.tipBonus);return total;
}
function effectStars(n,max=10){const x=Math.max(0,Math.min(5,Math.ceil((n||0)/max*5)));return '★'.repeat(x)+'☆'.repeat(5-x);}
function furnitureFeatureText(m){return `尺寸 ${m.foot?.[0]||1}×${m.foot?.[1]||1}｜${m.meta?.seats?`座位 ${m.meta.seats}`:(m.meta?.function||'裝潢')}`;}
renderCatalog=function(){
 const list=Object.entries(furniture).filter(([,m])=>state.category==='全部'||m.cat===state.category);
 els.catalog.innerHTML=list.map(([id,m])=>{const unlocked=isFurnitureUnlocked(id),lv=furnitureUnlockLevel(id),meta=furnitureMeta(id),newTag=V0481_NEW_IDS.has(id)?`<span class="new-furniture-tag">${unlocked?'NEW':'待解鎖'}</span>`:'';return `<button class="card furniture-rich-card ${unlocked?'':'locked-card'}" data-id="${id}" ${unlocked?'':'aria-disabled="true"'}>${newTag}<span class="owned">倉庫 ${state.inventory[id]||0}</span><img src="${m.img}" alt="${m.name}"><b>${m.name}</b><small class="f-level">Lv.${lv}｜🪙 ${money(m.price)}</small><small class="f-function">${furnitureFeatureText(m)}</small><span class="attribute-row"><i>舒適 ${meta.comfort}</i><i>魅力 ${meta.charm}</i><i>清潔 ${meta.cleaning>0?'-':''}${Math.abs(meta.cleaning)}</i></span>${unlocked?'':`<span class="unlock-rule">🔒 店鋪 Lv.${lv} 解鎖</span>`}</button>`}).join('');
 els.catalog.querySelectorAll('.card').forEach(btn=>btn.onclick=()=>{const id=btn.dataset.id;if(!isFurnitureUnlocked(id)){const lv=furnitureUnlockLevel(id),def=SHOP_LEVELS.find(x=>x.level===lv);toast(`需要店鋪 Lv.${lv}：${def?.name||''}`);return;}startPlace(id);});
 renderFurnitureEffectHud();
};
function renderFurnitureEffectHud(){
 let hud=document.getElementById('furnitureEffectHud');if(!hud){hud=document.createElement('button');hud.id='furnitureEffectHud';hud.type='button';hud.addEventListener('click',openFurnitureEffectPanel);document.getElementById('shopLevelHud')?.insertAdjacentElement('afterend',hud);}
 const e=placedFurnitureEffects();hud.innerHTML=`<b>🏡 店鋪屬性</b><span>舒適 ${e.comfort}　魅力 ${e.charm}　出餐 +${e.service}%</span>`;
}
function openFurnitureEffectPanel(){const e=placedFurnitureEffects();let panel=document.getElementById('furnitureEffectPanel');if(!panel){panel=document.createElement('div');panel.id='furnitureEffectPanel';panel.className='overlay-panel';panel.innerHTML=`<div class="effect-dialog"><button id="closeFurnitureEffects" class="close-x">×</button><h2>🏡 店鋪家具屬性</h2><div id="effectMetricGrid" class="effect-metric-grid"></div><h3>顧客偏好</h3><div id="preferenceList" class="preference-list"></div><p class="effect-note">家具屬性會實際影響顧客收益、人氣、小費、出餐速度、每日清潔與貓咪心情。</p></div>`;document.querySelector('.app').appendChild(panel);panel.querySelector('#closeFurnitureEffects').onclick=()=>panel.remove();panel.addEventListener('click',ev=>{if(ev.target===panel)panel.remove();});}
 panel.querySelector('#effectMetricGrid').innerHTML=[['舒適度',e.comfort,'提高顧客小費'],['裝潢魅力',e.charm,'提高人氣與拍照收益'],['清潔負擔',e.cleaning,'正值代表較難整理'],['出餐速度',e.service+'%','縮短點餐與用餐時間'],['貓咪心情',e.catMood,'隔日恢復加成'],['額外小費',e.tipBonus+'%','結帳時機率加成']].map(x=>`<div><small>${x[0]}</small><b>${x[1]}</b><span>${x[2]}</span></div>`).join('');
 panel.querySelector('#preferenceList').innerHTML=Object.entries(e.preferences).sort((a,b)=>b[1]-a[1]).map(([k,v])=>`<span>${k} × ${v}</span>`).join('')||'<span>尚未配置特色家具</span>';
}
const _v048SettleWithFurniture=settleCustomer;
settleCustomer=function(c){const beforeCoins=state.coins,beforeRep=state.reputation;_v048SettleWithFurniture(c);const e=placedFurnitureEffects();const prefText=(c.order?.name||'');let match=0;if(e.preferences['甜點']&&/蛋糕|鬆餅|布丁|甜點/.test(prefText))match=e.preferences['甜點'];else if(e.preferences['上班族']&&/咖啡|拿鐵|茶/.test(prefText))match=e.preferences['上班族'];else match=Math.max(0,...Object.values(e.preferences));const extraRep=Math.min(12,Math.floor(e.charm/18)+Math.floor(match/3)+Math.floor(e.repBonus/4));const extraTip=Math.random()<Math.min(.75,(e.comfort+e.charm)/260+e.tipBonus/100)?Math.max(4,Math.floor(e.comfort/5)+Math.floor(e.tipBonus/3)):0;if(extraRep||extraTip){state.reputation+=extraRep;state.dailyRep=(state.dailyRep||0)+extraRep;state.coins+=extraTip;state.dailyRevenue=(state.dailyRevenue||0)+extraTip;state.dailyTips=(state.dailyTips||0)+extraTip;toast(`家具加成：${extraRep?`人氣 +${extraRep} `:''}${extraTip?`小費 +${extraTip}`:''}`);renderStats();save();}};
